import { MakeLogicType, actions, connect, kea, path, reducers, selectors } from 'kea'
import { actionToUrl, urlToAction } from 'kea-router'

import { urls } from 'scenes/urls'

import { mcpGatewayLogic } from './mcpGatewayLogic'

export type GatewayTab = 'servers' | 'team' | 'settings' | 'audit'

export const ADMIN_TABS: GatewayTab[] = ['servers', 'team', 'settings', 'audit']
const MEMBER_TABS: GatewayTab[] = ['servers']

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface mcpGatewaySceneLogicValues {
    isAdmin: boolean // mcpGatewayLogic
    activeTab: GatewayTab
    availableTabs: GatewayTab[]
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface mcpGatewaySceneLogicActions {
    _setTab: (tab: GatewayTab) => {
        tab: GatewayTab
    }
    setTab: (tab: GatewayTab) => {
        tab: GatewayTab
    }
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface mcpGatewaySceneLogicMeta {
    __keaTypeGenInternalSelectorTypes: {
        availableTabs: (isAdmin: any) => GatewayTab[]
    }
}

export type mcpGatewaySceneLogicType = MakeLogicType<
    mcpGatewaySceneLogicValues,
    mcpGatewaySceneLogicActions,
    Record<string, any>,
    mcpGatewaySceneLogicMeta
>

/** URL-synced active tab (see data_warehouse SourceScene pattern: `setTab` writes
 * the URL, `_setTab` reacts to it without a feedback loop). */
export const mcpGatewaySceneLogic = kea<mcpGatewaySceneLogicType>([
    path(['products', 'mcp_store', 'frontend', 'gateway', 'mcpGatewaySceneLogic']),
    connect(() => ({ values: [mcpGatewayLogic, ['isAdmin']] })),
    actions({
        setTab: (tab: GatewayTab) => ({ tab }),
        _setTab: (tab: GatewayTab) => ({ tab }),
    }),
    reducers({
        activeTab: ['servers' as GatewayTab, { setTab: (_, { tab }) => tab, _setTab: (_, { tab }) => tab }],
    }),
    selectors({
        availableTabs: [(s) => [s.isAdmin], (isAdmin): GatewayTab[] => (isAdmin ? ADMIN_TABS : MEMBER_TABS)],
    }),
    actionToUrl(({ values }) => ({
        setTab: () => (values.activeTab === 'servers' ? urls.mcpGateway() : urls.mcpGatewayTab(values.activeTab)),
    })),
    urlToAction(({ actions, values }) => ({
        [urls.mcpGateway()]: () => {
            if (values.activeTab !== 'servers') {
                actions._setTab('servers')
            }
        },
        [urls.mcpGatewayTab(':tab')]: ({ tab }) => {
            const next = (ADMIN_TABS.includes(tab as GatewayTab) ? tab : 'servers') as GatewayTab
            if (next !== values.activeTab) {
                actions._setTab(next)
            }
        },
    })),
])
